mapper.select:
select count(1) from shop_apply_requests
where applicant_user_id = #{applicantUserId}
  and name = #{name}
  and address = #{address}
  and status = #{status}

mapper.update:
update shop_apply_requests
set status = #{status},
    reviewer_user_id = #{reviewerUserId},
    review_note = #{reviewNote},
    reviewed_at = #{reviewedAt}
where id = #{id} and status = #{expectedStatus}
